INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Rat', '쥐', '🐀', '지혜롭고 민첩한 쥐띠. 재주가 많고 적응력이 뛰어나다.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Ox', '소', '🐂', '성실하고 인내력 강한 소띠. 묵묵히 노력해 큰 성과를 만든다.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Tiger', '호랑이', '🐅', '용맹하고 카리스마 넘치는 호랑이띠. 타고난 리더십의 소유자.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Rabbit', '토끼', '🐇', '우아하고 섬세한 토끼띠. 평화를 사랑하고 창의력이 풍부하다.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Dragon', '용', '🐉', '강인하고 이상적인 용띠. 12지지 중 가장 길한 기운을 타고난다.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Snake', '뱀', '🐍', '심오하고 직관적인 뱀띠. 지혜와 통찰력으로 진실을 꿰뚫는다.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Horse', '말', '🐴', '자유롭고 열정적인 말띠. 불꽃처럼 타오르는 에너지의 소유자.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Goat', '양', '🐑', '온화하고 예술적인 양띠. 창의력과 공감능력이 뛰어나다.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Monkey', '원숭이', '🐒', '영리하고 다재다능한 원숭이띠. 문제 해결의 달인.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Rooster', '닭', '🐓', '부지런하고 완벽주의적인 닭띠. 날카로운 관찰력의 소유자.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Dog', '개', '🐕', '충직하고 정의로운 개띠. 신뢰와 성실함이 인생의 무기다.', 'ko') ON CONFLICT (animal) DO NOTHING;
INSERT INTO public.saju_content_zodiac (animal, kr, emoji, trait, language) VALUES ('Pig', '돼지', '🐗', '넉넉하고 순박한 돼지띠. 복이 많고 사람들에게 사랑받는다.', 'ko') ON CONFLICT (animal) DO NOTHING;
