INSERT INTO public.saju_content_day_master (day_master_id, title, hanja, nature, strength, caution, korean_style, lucky_color, lucky_color_hex, lucky_number, language) VALUES (7, '辛金 일간', '辛', '珠玉', ARRAY['완벽한 미적 감각','정밀함','귀족적 품위']::text[], ARRAY['예민함','비판적 성향']::text[], '강남 성형외과 원장 겸 주얼리 작가', '은색', '#cbd5e1', 9, 'ko') ON CONFLICT (day_master_id) DO NOTHING;
