INSERT INTO public.saju_content_day_master (day_master_id, title, hanja, nature, strength, caution, korean_style, lucky_color, lucky_color_hex, lucky_number, language) VALUES (9, '癸水 일간', '癸', '雨露', ARRAY['섬세한 직관','통찰력','내면의 깊이']::text[], ARRAY['과도한 내성적 성향','불안감']::text[], 'KAIST 뇌과학 연구자', '남색', '#818cf8', 6, 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (0, '아메리카노 한 잔 들고 성수동 스튜디오 출근. 팀원들보다 30분 먼저 도착해 하루를 설계한다.', '브랜드 피칭 미팅. 당신이 말을 시작하는 순간 방 안의 공기가 달라진다.', '이태원 루프탑 바에서 동료들과 위스키 한 잔. 아이디어 회의는 새벽 2시에 끝난다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (1, '익선동 한옥 카페 2층 창가 자리. 핸드드립 커피와 함께 스케치북을 펼친다.', '동대문 패브릭 시장을 누비며 다음 컬렉션의 영감을 수집한다.', '홍대 소규모 전시 오프닝에 참석. 작가와 한 시간 동안 예술론을 나눈다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (2, '여의도 방송국 분장실. 뉴스 앵커 의자에 앉는 순간 다른 사람이 된다.', '생방송 뉴스 진행. 300만 시청자가 당신의 목소리를 기다린다.', '강남 한식당에서 PD들과 저녁 식사. 다음 시즌 프로그램 기획안을 그림처럼 그린다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (3, '청담동 뷰티 스튜디오. 당신이 만든 팔레트 신제품 출시일 아침.', '뷰티 에디터 인터뷰와 화보 촬영 디렉팅. 모든 컷이 당신의 머릿속 그림과 일치한다.', '가로수길 전시관에서 작은 개인전 오프닝. 작품마다 당신의 손길이 살아있다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (4, '여의도 63빌딩 42층 임원실. 서울이 발아래 펼쳐진다.', '외국계 파트너사와 전략적 M&A 협상. 당신의 한 마디가 수백억을 움직인다.', '한강 크루즈 비즈니스 디너. 서울의 야경을 배경으로 미래를 설계한다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (5, '서울대학교 강의실. 200명의 학생들이 당신이 열기를 기다린다.', '연구실에서 논문 검토. 한국 교육의 새 패러다임을 써 내려간다.', '광화문 광장 근처 조용한 국밥 한 그릇. 다음 학기 강의안을 노트에 정리한다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (6, '서초동 대형 로펌 35층. 창밖으로 법원 청사가 보인다.', '헌법재판소 최종 변론. 당신의 논리는 칼날처럼 정교하다.', '청담동 일식집에서 동료 변호사들과 조용한 식사. 내일의 전략을 다듬는다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (7, '청담동 의원 첫 환자 전 10분, 현미경 앞에서 명상처럼 준비한다.', '복잡한 재건 수술 집도. 당신의 손은 예술가의 손이다.', '이태원 주얼리 아틀리에에서 신작 제작. 의학과 예술이 하나가 되는 시간.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (8, '판교 네이버 본사. 새벽 6시에 도착해 가장 조용한 시간에 코드를 짠다.', 'AI 모델 성능 리뷰 미팅. 당신의 인사이트에 팀원들이 메모를 멈추지 않는다.', '서울숲 야외에서 맥북을 펴고 사이드 프로젝트 작업. 별빛 아래 알고리즘을 꿈꾼다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_daily_scenario (day_master_id, morning, afternoon, evening, language) VALUES (9, '카이스트 연구동. 뇌파 데이터를 보며 어제 꿈에서 떠오른 가설을 검증한다.', '국제 학술지 논문 제출. 한국이 세계 뇌과학의 중심이 되는 날을 앞당긴다.', '신촌 조용한 찻집. 철학책 한 권과 녹차 한 잔으로 하루를 닫는다.', 'ko') ON CONFLICT (day_master_id) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('甲', '개척자의 혈통', '先驅 · 개척', '당신의 가문에는 남보다 먼저 새길을 여는 DNA가 흐릅니다. 어린 시절부터 "왜?"를 멈추지 않았고, 선생님들은 당신을 "유독 고집스러운 아이"라 불렀을 것입니다. 그 고집은 사실 甲木의 뿌리 — 하늘을 향해 자라려는 불굴의 의지였습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('乙', '감수성의 씨앗', '感性 · 유연', '유년의 당신은 남들이 지나치는 것들을 유독 오래 바라보았습니다. 꽃 한 송이, 교실 창밖의 빗줄기, 친구의 표정 변화. 乙木의 기운은 환경에 맞추어 유연하게 자라는 덩굴처럼, 당신의 어린 시절을 섬세한 관찰과 풍부한 감수성으로 채웠습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('丙', '빛의 기원', '光明 · 열정', '어린 시절의 당신은 방에서 가장 밝은 존재였습니다. 발표 때 손을 번쩍 들고, 운동회에서 앞장서고, 무대에 오를 때 두려움 대신 설렘을 느꼈던 아이. 丙火의 태양 에너지는 태어날 때부터 당신 안에서 타오르고 있었습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('丁', '집중의 불꽃', '精密 · 완성', '당신의 유년은 "하나에 꽂히면 끝을 봐야 하는" 기질로 가득했습니다. 레고 하나를 완성할 때까지 밥도 잊고, 그림 하나를 완벽하게 만들 때까지 지우개가 닳도록 반복했던 아이. 丁火의 집중된 불꽃이 일찍부터 당신 안에 깃들었습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('戊', '산의 침묵', '泰山 · 근원', '어린 시절의 당신은 또래보다 조금 더 무게감이 있었습니다. 쉽게 흥분하지 않고, 결정을 내리면 잘 바꾸지 않았으며, 친구들은 무의식적으로 당신에게 기댔습니다. 戊土의 산 기운은 아주 어릴 때부터 당신을 든든한 중심으로 만들었습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('己', '비옥한 토양', '包容 · 배양', '어릴 적 당신의 집은 친구들이 자주 모이는 곳이었을 것입니다. 누군가 상처받으면 먼저 다가가고, 외로운 아이의 옆자리에 자연스레 앉았던 아이. 己土의 기름진 대지처럼, 당신은 주변을 싹틔우는 따뜻한 토양으로 자라났습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('庚', '단련의 서막', '鍛鍊 · 원칙', '유년의 당신에게 불공평함은 참을 수 없는 것이었습니다. 규칙이 지켜지지 않을 때, 약자가 억울하게 당할 때 목소리를 높였습니다. 庚金의 날선 검처럼, 당신의 어린 시절은 원칙과 정의를 향한 날카로운 감각이 형성되는 시간이었습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('辛', '보석의 원석', '精製 · 심미', '어린 시절부터 당신의 눈은 달랐습니다. 같은 물건도 더 아름다운 것을 고르고, 방을 꾸미는 방식이 어른스러웠으며, 이미 어릴 때부터 "미적 감각이 있다"는 말을 들었을 것입니다. 辛金의 정제된 빛이 원석 형태로 당신 안에 잠들어 있었습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('壬', '깊은 강의 시작', '智慧 · 호기심', '당신의 유년기는 질문으로 가득했습니다. 왜 하늘은 파란지, 사람은 왜 죽는지, 우주 끝에는 무엇이 있는지. 부모님도 답하기 어려운 질문을 쏟아내던 아이. 壬水의 대해처럼 광대한 지적 호기심이 그 시절부터 당신을 이끌었습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_past (stem_key, title, keyword, narrative, language) VALUES ('癸', '안개 속 직관', '洞察 · 감응', '어릴 때부터 당신은 뭔가 달랐습니다. 말하지 않아도 상대방의 감정을 느끼고, 일이 일어나기 전에 이미 알 것 같은 느낌을 받았습니다. 癸水의 안개비처럼 조용하고 깊은 직관이 아주 어린 시절부터 당신의 내면에 스며 있었습니다.', 'ko') ON CONFLICT (stem_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('寅', '호랑이처럼 질주한 청춘', '勇猛 · 개척', '10대와 20대의 당신은 멈추지 않았습니다. 경험할 수 있는 것은 모두 경험하려 했고, 위험해 보이는 선택도 두려워하지 않았습니다. 寅의 호랑이 기운이 청춘의 당신을 앞으로, 앞으로 밀었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('卯', '봄의 감성으로 핀 청춘', '成長 · 창조', '당신의 청춘은 꽃피는 봄처럼 섬세하고 아름다웠습니다. 좋아하는 것에 빠져들었고, 감수성이 예술이나 글쓰기, 음악으로 흘러넘쳤습니다. 卯의 봄 기운이 당신의 10~20대를 창조와 감성의 시절로 만들었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('辰', '용의 기운으로 도약한 청춘', '抱負 · 도약', '당신의 청춘에는 거대한 포부가 있었습니다. 평범한 길을 걷기 싫었고, 뭔가 큰 것을 이루겠다는 막연하지만 강렬한 확신이 있었습니다. 辰의 용 기운이 당신의 청춘을 야망의 시절로 채웠습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('巳', '뱀의 지혜로 읽어낸 청춘', '洞察 · 전략', '당신의 10~20대는 사람과 상황을 읽는 법을 배우는 시간이었습니다. 관계의 복잡한 역학을 일찍 파악했고, 말 한마디의 무게를 또래보다 먼저 이해했습니다. 巳의 통찰이 당신을 성숙하게 만든 청춘이었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('午', '불꽃처럼 타오른 청춘', '熱情 · 표현', '당신의 청춘은 뜨거웠습니다. 사랑도 우정도 공부도 열정적으로 쏟아부었고, 중간이 없었습니다. 午의 불꽃 에너지가 당신의 10~20대를 온 몸이 달아오르는 열정의 시절로 만들었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('未', '양떼처럼 따뜻했던 청춘', '友情 · 연대', '당신의 청춘은 사람으로 가득했습니다. 친구들과 밤새 이야기하고, 누군가의 고민을 들어주며 새벽을 보냈습니다. 未의 온화한 기운이 당신의 10~20대를 따뜻한 연대와 우정으로 채웠습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('申', '원숭이처럼 영리했던 청춘', '智略 · 적응', '당신의 청춘은 빠른 두뇌 회전이 돋보이는 시절이었습니다. 새로운 것을 금방 익히고, 상황에 맞춰 유연하게 전략을 바꾸었습니다. 申의 영리한 기운이 당신을 또래 중 가장 빠른 학습자로 만들었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('酉', '닭처럼 부지런했던 청춘', '完美 · 노력', '당신의 10~20대는 성실함의 시절이었습니다. 남들이 자는 시간에 공부하고, 완성도에 집착하며 결과물을 다듬었습니다. 酉의 완벽주의 기운이 당신의 청춘을 치열한 자기 단련의 시간으로 만들었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('戌', '개처럼 충직했던 청춘', '義理 · 신뢰', '당신의 청춘은 의리의 시절이었습니다. 한번 친구가 된 사람은 끝까지 챙겼고, 배신보다 손해를 택하는 선택을 반복했습니다. 戌의 충직한 기운이 당신을 가장 믿음직한 친구로 만든 시절이었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('亥', '깊은 물처럼 흘렀던 청춘', '自由 · 탐구', '당신의 청춘은 자유를 갈망했습니다. 정해진 틀이 답답했고, 새로운 세계와 사람을 탐험하고 싶었습니다. 亥의 물 기운이 당신을 경계 없이 흐르며 세상을 넓게 경험한 탐험가로 만들었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('子', '자시처럼 고요했던 청춘', '蓄積 · 내면', '당신의 청춘은 조용하지만 깊었습니다. 화려하지 않았지만, 내면에서 엄청난 것들이 축적되고 있었습니다. 子의 밤의 기운이 당신을 겉으로 드러나지 않아도 안에서 단단히 성장하는 사람으로 만들었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_youth (branch_key, title, keyword, narrative, language) VALUES ('丑', '소처럼 묵묵히 걸은 청춘', '忍耐 · 蓄積', '당신의 청춘은 화려하지 않아도 충실했습니다. 남들이 지름길을 찾을 때 당신은 정도를 걸었습니다. 丑의 소 기운이 당신의 청춘을 느리지만 절대 흔들리지 않는 묵묵한 성장의 시간으로 만들었습니다.', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('甲', '숲을 이루는 시대', '創業 · 유산', '당신의 절정은 아직 오지 않았습니다. 앞으로의 시간은 지금까지 심어온 씨앗들이 울창한 숲을 이루는 시기입니다. 40~55세 사이, 당신은 이름을 남기는 무언가를 완성하게 됩니다. 사람들이 당신에게 기대게 되고, 당신은 그 무게를 기꺼이 받아들이는 리더가 됩니다.', '40~55세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('乙', '꽃이 피는 전성기', '開花 · 인정', '당신의 미래는 드디어 세상이 당신을 알아보는 시간입니다. 오랫동안 조용히 키워온 실력과 감각이 빛을 발하고, 예상치 못한 방향에서 기회가 찾아옵니다. 35~50세의 당신은 인생의 가장 아름다운 꽃을 피웁니다.', '35~50세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('丙', '태양이 중천에 뜨는 시대', '全盛 · 영향력', '미래의 당신 앞에는 더 넓은 무대가 기다리고 있습니다. 지금의 영향력이 지역을 넘어 더 넓은 세계로 뻗어 나가고, 당신의 이름은 한국을 넘어 아시아, 그리고 세계에서 언급될 것입니다.', '35~50세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('丁', '마스터피스를 완성하는 시대', '完成 · 傑作', '미래의 당신은 평생의 작업을 완성하게 됩니다. 서두르지 않아도 됩니다. 丁火는 천천히, 정밀하게 타오르는 불꽃. 40~60세 사이 당신이 완성하는 것은 분야에 관계없이 오랫동안 기억될 것입니다.', '40~60세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('戊', '산이 되는 시대', '確立 · 권위', '미래의 당신은 흔들리지 않는 산이 됩니다. 45세 이후, 당신의 존재감은 더욱 단단해지고 많은 사람들이 당신에게 방향을 묻습니다. 조직이든 가정이든, 당신은 모두가 믿고 기댈 수 있는 중심이 됩니다.', '45~65세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('己', '수확의 계절', '結實 · 풍요', '미래의 당신에게 풍요가 찾아옵니다. 지금까지 사람들에게 아낌없이 쏟아온 것들이 예상치 못한 방식으로 되돌아옵니다. 물질적 안정, 신뢰받는 관계, 깊어진 지혜 — 40~55세의 당신은 진정한 수확의 계절을 맞이합니다.', '40~55세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('庚', '명검이 완성되는 시대', '完鍊 · 최고점', '당신의 날카로움은 앞으로 더욱 정교해집니다. 미래의 당신은 분야에서 최고 권위자 중 한 명이 됩니다. 말 한마디가 결정을 바꾸고, 판단이 조직의 방향을 결정합니다. 庚金의 검은 단련을 거칠수록 예리해집니다.', '40~55세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('辛', '보석이 광채를 내는 시대', '名聲 · 빛남', '미래의 당신은 오랫동안 갈고 닦아온 것들이 마침내 세상에서 빛나기 시작합니다. 35~55세 사이, 당신의 이름 앞에 수식어가 붙기 시작하고, 당신이 만든 것들이 당신의 존재보다 먼저 알려지게 됩니다.', '35~55세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('壬', '대해가 완성되는 시대', '深化 · 影響', '미래의 당신은 더 넓고 깊어집니다. 지금까지 모아온 지식과 경험이 45세 이후 하나의 거대한 흐름으로 통합됩니다. 당신이 남기는 것은 사람들의 생각 방식을 바꾸는 깊은 통찰입니다.', '45~65세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_narrative_future (branch_key, title, keyword, narrative, peak, language) VALUES ('癸', '고요한 강이 바다에 닿는 시대', '悟道 · 해방', '미래의 당신은 드디어 자기 자신을 완전히 이해하는 시간에 이릅니다. 40~60세 사이, 지금까지의 불안과 물음표들이 하나씩 해소되고, 내면의 고요함과 함께 진정한 자유를 경험하게 됩니다. 그 평화가 당신 주변을 변화시킵니다.', '40~60세', 'ko') ON CONFLICT (branch_key) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('wood', 'male', '강재우', 'Jae-woo Kang', 'Decisive & Structured', 'Quietly Ambitious', 'Understated Elegance', '庚金의 에너지. 당신의 광범위한 비전에 아름다운 형태를 부여하는 정확하고 흔들리지 않는 신념을 가진 사람. 당신이 자유롭게 상상하는 곳에서, 그는 흠잡을 데 없이 실행합니다.', 94, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('wood', 'female', '이서진', 'Seo-jin Lee', 'Meticulous & Principled', 'Quietly Confident', 'Appreciates Depth', '庚金의 에너지. 당신의 광대한 木 에너지를 단단하게 잡아주는 구조와 결단력의 명료함을 지닌 사람. 당신이 자유롭게 뻗어 나가는 곳에서, 그녀는 당신에게 우아한 형태를 부여합니다.', 94, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('fire', 'male', '김민우', 'Min-woo Kim', 'Introspective & Wise', 'Deeply Calm', 'Intellectually Boundless', '壬水의 에너지. 당신의 불꽃이 필요로 하면서도 저항하는 깊은 고요함을 지닌 사람. 그의 존재 안에서 당신의 열정은 철학적 토대를 찾고, 그의 광대한 지성은 따뜻함을 찾습니다.', 91, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('fire', 'female', '박수현', 'Su-hyeon Park', 'Deeply Calm', 'Intellectually Vast', 'Emotionally Intuitive', '壬水의 에너지. 당신의 찬란한 불꽃을 식히고 집중시키는 고요한 지성으로 흐르는 사람. 당신의 열정은 그녀의 반영을 통해 깊이를 찾고, 그녀의 고요한 물은 당신의 따뜻함 안에서 색깔을 찾습니다.', 91, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('earth', 'male', '이지훈', 'Ji-hun Lee', 'Creatively Visionary', 'Boldly Original', 'Restlessly Alive', '甲木의 에너지. 당신의 안정적인 Earth가 열망하면서도 두려워하는 창의적 불과 개척 정신을 가진 사람. 당신은 그에게 절실히 필요한 기반을 주고, 그는 당신에게 진정한 성장만이 제공할 수 있는 방향을 줍니다.', 89, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('earth', 'female', '최가은', 'Ka-eun Choi', 'Imaginative & Free', 'Spontaneously Warm', 'Creatively Fearless', '甲木의 에너지. 당신의 깊이 뿌리내린 패턴에서 당신을 깨워내는 창의적 불안과 개척 정신을 가진 사람. 당신의 안정��� 그녀의 탁월한 아이디어가 꽃피울 토양이 됩니다.', 89, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('metal', 'male', '박도현', 'Do-hyeon Park', 'Deeply Passionate', 'Radiantly Warm', 'Charismatically Alive', '丙火의 에너지. 당신의 金 에너지를 진정한 빛남으로 정제하는 강력한 힘. 당신이 정밀함에서 완벽을 추구하는 곳에서, 그는 진정한 연결의 원초적 힘에서 그것을 찾습니다.', 96, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('metal', 'female', '정나은', 'Na-eun Jung', 'Warmly Intuitive', 'Brilliantly Charismatic', 'Emotionally Generous', '丁火의 에너지. 당신의 金 빛남을 최고의 광채로 연마하는 부드럽고 찬란한 따뜻함을 가진 사람. 당신의 정밀함이 그녀의 빛 속에서 빛나게 되고, 그녀의 불꽃은 당신의 정제된 형태에서 완벽한 용기를 찾습니다.', 96, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('water', 'male', '윤태현', 'Tae-hyeon Yun', 'Immovably Grounded', 'Quietly Strong', 'Traditionally Rooted', '戊土의 에너지. 당신의 Water가 주위를 흐르고, 통과하고, 결국 형성하는 산. 그의 흔들리지 않는 안정성이 당신의 광대한 지성에 필요한 용기를 제공합니다.', 88, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_soulmate (element, gender, name, name_romanized, trait1, trait2, trait3, description, compatibility_score, language) VALUES ('water', 'female', '조하영', 'Ha-young Jo', 'Steady & Reliable', 'Grounded in Tradition', 'Profoundly Patient', '己土의 에너지. 당신의 흐르는 水 본성에 아름다운 정의를 부여하는 강둑. 그녀 없이는 무한한 반영 속에서 자신을 잃을 수 있지만, 그녀와 함께라면 당신의 깊이는 심연이 아닌 목적지가 됩니다.', 88, 'ko') ON CONFLICT (element, gender) DO NOTHING;
INSERT INTO public.saju_content_neighborhood (element, name, name_kr, description, vibe, language) VALUES ('wood', 'Hongdae', '홍대 · 홍익대학교 앞', '한국 청년 문화와 창조성의 심장. 벽화, 독립 갤러리, 라이브 뮤직, 아방가르드 카페 속에서 당신의 木 기운이 자유롭게 피어납니다.', 'Creative · Free-spirited · Bohemian', 'ko') ON CONFLICT (element) DO NOTHING;
INSERT INTO public.saju_content_neighborhood (element, name, name_kr, description, vibe, language) VALUES ('fire', 'Gangnam', '강남구 · 압구정 로데오', '야망이 럭셔리를 만나는 곳. 미슐랭 레스토랑, 글로벌 패션 하우스, 파워 코리더가 즐비한 이 ZIP 코드는 당신의 火 에너지가 사령탑에 앉을 자리입니다.', 'Dynamic · Prestigious · High-achieving', 'ko') ON CONFLICT (element) DO NOTHING;
INSERT INTO public.saju_content_neighborhood (element, name, name_kr, description, vibe, language) VALUES ('earth', 'Bukchon', '북촌 한옥마을', '600년 된 한옥과 궁궐 사이에 보존된 세계. 전통이 살아있는 예술인 이 동네에서 당신의 土 기운은 가장 깊은 울림을 찾습니다.', 'Grounded · Traditional · Serene', 'ko') ON CONFLICT (element) DO NOTHING;
INSERT INTO public.saju_content_neighborhood (element, name, name_kr, description, vibe, language) VALUES ('metal', 'Hannam-dong', '한남동', '교양 있는 엘리트들의 가장 탐나는 주소. 컨셉 스토어, 프라이빗 아트 갤러리, 쉐프''s 테이블 레스토랑이 자리한 이곳은 당신의 金 기운이 완전히 빛나는 무대입니다.', 'Refined · Exclusive · Understated luxury', 'ko') ON CONFLICT (element) DO NOTHING;
INSERT INTO public.saju_content_neighborhood (element, name, name_kr, description, vibe, language) VALUES ('water', 'Mapo-gu', '마포구 · 연남동', '한강변을 따라 독립 출판사, 스페셜티 커피 로스터, 언더그라운드 뮤직이 흐르는 마포. 당신의 水 에너지는 이 고유한 전류 속에서 가장 자유롭게 흐릅니다.', 'Intellectual · Artistic · Fluid', 'ko') ON CONFLICT (element) DO NOTHING;
